import "./App.css";
import { Songs } from "./pages/Songs";
import { Navbar } from "./components/Navbar";
import { BrowserRouter as Router, Routes, Route, Link } from "react-router-dom";

function App() {
	return (
		<div className="App">
			<Router>
				<Routes>
					<Route></Route>
				</Routes>
			</Router>
			<Navbar />
			<Songs />
		</div>
	);
}

export default App;
